import React, { useState, useEffect, useRef } from 'react';
import { SearchMode, Jurisdiction, HistoryItem } from '../types';

interface HeroSectionProps {
  query: string;
  setQuery: (q: string) => void;
  mode: SearchMode;
  setMode: (m: SearchMode) => void;
  jurisdiction: Jurisdiction;
  setJurisdiction: (j: Jurisdiction) => void;
  onSearch: () => void;
  isLoading: boolean;
  history: HistoryItem[];
  onHistorySelect: (item: HistoryItem) => void;
}

// Mock database for autocomplete demo
const MOCK_CASE_DB = [
  "Kesavananda Bharati v. State of Kerala",
  "Maneka Gandhi v. Union of India",
  "Minerva Mills Ltd. v. Union of India",
  "Golaknath v. State of Punjab",
  "Shah Bano Begum Case",
  "Vishaka v. State of Rajasthan",
  "Puttaswamy v. Union of India (Privacy Case)",
  "Indra Sawhney v. Union of India",
  "ADM Jabalpur v. Shivkant Shukla",
  "S.R. Bommai v. Union of India",
  "Naz Foundation v. Govt. of NCT of Delhi",
  "Navtej Singh Johar v. Union of India",
  "Shayara Bano v. Union of India (Triple Talaq)",
  "M.C. Mehta v. Union of India",
  "Common Cause v. Union of India",
  "D.K. Basu v. State of West Bengal",
  "Mohd. Ahmed Khan v. Shah Bano Begum",
  "Bachchan Singh v. State of Punjab",
  "Olga Tellis v. Bombay Municipal Corporation"
];

export const HeroSection: React.FC<HeroSectionProps> = ({
  query,
  setQuery,
  mode,
  setMode,
  jurisdiction,
  setJurisdiction,
  onSearch,
  isLoading,
  history,
  onHistorySelect
}) => {
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const wrapperRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Autocomplete logic
    if (mode === SearchMode.CASE_NAME && query.length > 2) {
      const filtered = MOCK_CASE_DB.filter(c => 
        c.toLowerCase().includes(query.toLowerCase())
      ).slice(0, 5);
      setSuggestions(filtered);
      setShowSuggestions(filtered.length > 0);
    } else {
      setShowSuggestions(false);
    }
  }, [query, mode]);

  // Click outside to close
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [wrapperRef]);

  const handleSuggestionClick = (suggestion: string) => {
    setQuery(suggestion);
    setShowSuggestions(false);
  };

  return (
    <div className="relative pt-32 pb-20 px-4 overflow-hidden min-h-[70vh] flex flex-col justify-center">

      {/* Background Decorative Elements */}
      <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[1200px] h-[800px] bg-navy-800/30 rounded-full blur-[150px] -z-10 pointer-events-none"></div>

      <div className="max-w-7xl mx-auto text-center relative z-10 w-full">

        {/* Logo Section */}
        <div className="mb-14 animate-fade-in-down flex flex-col items-center">

          <div className="relative w-32 h-32 mb-6 group cursor-default">
             <div className="absolute inset-0 bg-gold-500/20 blur-3xl rounded-full opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>
             <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-2xl overflow-visible">
               <defs>
                 <linearGradient id="goldGrad" x1="0%" y1="0%" x2="100%" y2="100%">
                   <stop offset="0%" stopColor="#d97706" />
                   <stop offset="50%" stopColor="#fbbf24" />
                   <stop offset="100%" stopColor="#d97706" />
                 </linearGradient>
               </defs>
               <path d="M50 10 L85 25 V 55 Q 85 85 50 95 Q 15 85 15 55 V 25 Z" fill="none" stroke="url(#goldGrad)" strokeWidth="1.5" className="opacity-50" />
               <path d="M40 25 V 65 Q 40 80 25 80" fill="none" stroke="url(#goldGrad)" strokeWidth="7" strokeLinecap="square" />
               <path d="M60 25 V 80 H 80" fill="none" stroke="url(#goldGrad)" strokeWidth="7" strokeLinecap="square" />
               <line x1="50" y1="20" x2="50" y2="85" stroke="#fbbf24" strokeWidth="2" className="opacity-60" strokeDasharray="3 3" />
             </svg>
          </div>

          <div className="inline-flex items-center justify-center px-8 py-3 mb-8 border-y border-gold-600/30 bg-navy-950/40 backdrop-blur-md">
            <span className="text-gold-400 text-sm font-cinzel tracking-[0.4em] font-bold uppercase drop-shadow-sm">
              Est. 2026 • AI Legal Research
            </span>
          </div>

          <h1 className="font-display text-8xl md:text-9xl lg:text-[10rem] font-bold mb-6 tracking-tighter text-parchment-50 drop-shadow-2xl relative inline-block">
            Juris<span className="text-shine italic font-serif font-light animate-shine text-yellow-500">Lens</span>
          </h1>

          <div className="flex items-center justify-center gap-6 my-8 opacity-80">
            <div className="h-px w-32 bg-gradient-to-r from-transparent to-gold-500"></div>
            <p className="text-slate-200 text-3xl font-serif italic tracking-wide">
              "Fiat Justitia Ruat Caelum"
            </p>
            <div className="h-px w-32 bg-gradient-to-l from-transparent to-gold-500"></div>
          </div>
        </div>

        {/* Search Interface - LARGER FONTS */}
        {!isLoading && (
          <div ref={wrapperRef} className="bg-navy-950/95 backdrop-blur-3xl rounded shadow-[0_30px_100px_rgba(0,0,0,0.8)] border border-slate-600 p-8 max-w-7xl mx-auto transform transition-all hover:border-gold-500/50 group hover:shadow-[0_30px_100px_rgba(251,191,36,0.15)] relative z-50">
            <div className="flex flex-col md:flex-row gap-6">

              <div className="relative min-w-[240px] bg-navy-900 rounded border border-slate-600">
                <select
                  value={mode}
                  onChange={(e) => setMode(e.target.value as SearchMode)}
                  className="w-full h-full p-6 bg-transparent text-white font-cinzel text-lg font-bold tracking-wider outline-none appearance-none cursor-pointer hover:text-gold-400 transition-colors"
                >
                  <option value={SearchMode.CASE_NAME}>CASE NAME / ISSUE</option>
                  <option value={SearchMode.CITATION}>CITATION</option>
                  <option value={SearchMode.TEXT_ANALYSIS}>RAW TEXT</option>
                </select>
                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-gold-500">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
                </div>
              </div>

              <div className="flex-grow relative bg-navy-900 rounded border border-slate-600 focus-within:border-gold-500 transition-colors">
                {mode === SearchMode.TEXT_ANALYSIS ? (
                  <textarea 
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    placeholder="Paste full judgment text..."
                    className="w-full p-6 bg-transparent text-white placeholder-slate-400 outline-none resize-none h-24 leading-relaxed font-serif text-xl font-medium"
                  />
                ) : (
                  <input
                    type="text"
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && onSearch()}
                    placeholder="Search case name, legal issue (e.g., 'triple talaq'), or use Boolean (AND, OR, NOT)..."
                    className="w-full h-full p-6 bg-transparent text-white placeholder-slate-400 outline-none font-serif text-3xl font-medium"
                    autoComplete="off"
                  />
                )}

                {/* Autocomplete Dropdown */}
                {showSuggestions && (
                  <div className="absolute left-0 right-0 top-full mt-2 bg-navy-900 border border-slate-500 rounded shadow-2xl overflow-hidden z-[100]">
                    {suggestions.map((s, i) => (
                      <button 
                        key={i}
                        onClick={() => handleSuggestionClick(s)}
                        className="w-full text-left px-8 py-5 text-white text-xl hover:bg-slate-800 hover:text-gold-400 font-serif border-b border-slate-700 last:border-0 transition-colors"
                      >
                        {s}
                      </button>
                    ))}
                  </div>
                )}
              </div>

              {mode !== SearchMode.TEXT_ANALYSIS && (
                 <div className="relative min-w-[200px] bg-navy-900 rounded border border-slate-600">
                 <select
                   value={jurisdiction}
                   onChange={(e) => setJurisdiction(e.target.value as Jurisdiction)}
                   className="w-full h-full p-6 bg-transparent text-white text-sm font-cinzel font-bold tracking-widest outline-none appearance-none cursor-pointer hover:text-gold-400 transition-colors uppercase"
                 >
                   {Object.values(Jurisdiction).map((j) => (
                     <option key={j} value={j}>{j}</option>
                   ))}
                 </select>
                 <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
                 </div>
               </div>
              )}

              <button
                onClick={onSearch}
                disabled={!query.trim()}
                className="bg-gold-600 hover:bg-gold-500 disabled:bg-slate-800 disabled:text-slate-600 text-black font-cinzel font-bold text-xl py-4 px-14 transition-all duration-300 flex items-center justify-center gap-3 min-w-[200px] shadow-[inset_0_0_20px_rgba(255,255,255,0.2)] rounded border-t border-b border-gold-400 hover:shadow-[0_0_30px_rgba(251,191,36,0.6)]"
              >
                 <span className="tracking-widest">SEARCH</span>
              </button>
            </div>

            {/* Search History Integration */}
            {history.length > 0 && (
              <div className="mt-8 flex items-center gap-4 overflow-x-auto pb-4 scrollbar-thin">
                <span className="text-sm text-slate-400 font-bold uppercase tracking-wider shrink-0 mr-2">RECENT:</span>
                {history.map((item, idx) => (
                   <button 
                     key={idx}
                     onClick={() => onHistorySelect(item)}
                     className="shrink-0 flex items-center gap-3 px-5 py-3 bg-navy-900 border border-slate-700 rounded hover:border-gold-500 group transition-all"
                   >
                     <span className="text-sm text-slate-200 font-mono group-hover:text-gold-400 font-bold">{item.query}</span>
                     <span className="text-[10px] bg-black/60 px-2 py-1 rounded text-slate-300 font-bold border border-slate-700">{item.jurisdiction.slice(0,3).toUpperCase()}</span>
                   </button>
                ))}
              </div>
            )}

          </div>
        )}

      </div>
    </div>
  );
};

import React from 'react';
import { CaseSearchResult } from '../types';

interface CaseListProps {
  results: CaseSearchResult[];
  onSelect: (result: CaseSearchResult) => void;
}

export const CaseList: React.FC<CaseListProps> = ({ results, onSelect }) => {
  return (
    <div className="max-w-5xl mx-auto px-4 mb-24">
      <div className="text-center mb-12">
        <h2 className="font-display text-4xl text-parchment-50 mb-4 font-bold">Select Case Record</h2>
        <div className="flex items-center justify-center gap-4 text-gold-500 font-cinzel text-sm tracking-widest font-bold">
           <span>MULTIPLE PRECEDENTS FOUND</span>
           <div className="h-0.5 w-16 bg-gold-600/50"></div>
        </div>
      </div>

      <div className="grid gap-6">
        {results.map((result, idx) => (
          <div
            key={idx}
            className="group relative bg-navy-900/80 border border-slate-600 hover:border-gold-500 p-8 rounded-lg transition-all duration-300 hover:shadow-[0_0_40px_rgba(234,179,8,0.15)] hover:-translate-y-1 flex flex-col gap-4"
          >
            <button onClick={() => onSelect(result)} className="text-left w-full">
              <div className="flex justify-between items-start mb-4">
                <h3 className="font-display text-3xl font-bold text-parchment-50 group-hover:text-gold-400 transition-colors leading-tight">
                  {result.caseName}
                </h3>
                <span className="text-sm font-mono text-slate-300 bg-black/40 px-3 py-1.5 border border-slate-700 rounded whitespace-nowrap ml-4">
                  {result.citation}
                </span>
              </div>

              <p className="text-slate-300 font-serif italic text-xl border-l-4 border-slate-600 pl-6 group-hover:border-gold-500 transition-colors leading-relaxed">
                "{result.context}"
              </p>
            </button>

            {/* Display Found PDF Links */}
            {result.sourceUrls && result.sourceUrls.length > 0 && (
              <div className="mt-4 pt-4 border-t border-slate-700 flex flex-wrap gap-3">
                <span className="text-xs text-slate-400 uppercase tracking-widest font-black self-center mr-2">DIRECT SOURCES:</span>
                {result.sourceUrls.map((source, i) => (
                  <a 
                    key={i}
                    href={source.url}
                    target="_blank"
                    rel="noreferrer"
                    className="text-xs px-3 py-1.5 bg-navy-950 border border-slate-600 rounded text-slate-300 hover:text-gold-400 hover:border-gold-500 transition-colors font-bold uppercase tracking-wider"
                    onClick={(e) => e.stopPropagation()} // Prevent triggering parent button click
                  >
                    {source.source || 'View PDF'} ↗
                  </a>
                ))}
              </div>
            )}

            <div className="absolute bottom-0 left-0 w-0 h-1 bg-gold-600 group-hover:w-full transition-all duration-500 ease-out"></div>
          </div>
        ))}
      </div>

      <div className="text-center mt-12">
        <p className="text-slate-500 text-sm font-cinzel tracking-widest font-bold">
          SELECT THE RELEVANT PRECEDENT TO PROCEED
        </p>
      </div>
    </div>
  );
};

import React, { useEffect } from 'react';
import { CaseSummary } from '../types';

