           <div className="flex items-center gap-8">
              <span className={`font-cinzel font-black text-base tracking-widest ${isVakilMode ? 'text-neon-green' : 'text-slate-900'}`}>JUDGMENT READER</span>
              <div className="h-8 w-px bg-slate-500/30"></div>
