           <div className={`w-full max-w-[1100px] min-h-full p-12 md:p-20 shadow-2xl ${isVakilMode ? 'bg-zinc-950 border border-zinc-700' : 'bg-white'}`}>

              {/* Document Header */}
              <div className="text-center mb-20 pb-12 border-b-4 border-double border-slate-300/50">
                 <div className="w-24 h-24 mx-auto mb-8 opacity-60 bg-[url('https://upload.wikimedia.org/wikipedia/commons/5/55/Emblem_of_India.svg')] bg-contain bg-no-repeat bg-center grayscale"></div>
                 <h2 className={`font-cinzel text-4xl md:text-5xl font-black mb-4 ${isVakilMode ? 'text-slate-100' : 'text-black'}`}>IN THE SUPREME COURT OF INDIA</h2>
                 <p className="font-serif italic text-2xl text-slate-500 font-medium">{summary.jurisdiction} Appellate Jurisdiction</p>
                 <p className={`font-mono text-base mt-8 py-3 px-6 inline-block rounded font-bold ${isVakilMode ? 'bg-zinc-900 text-gray-300' : 'bg-slate-100 text-slate-800'}`}>{summary.citation}</p>
              </div>

              {/* Pseudo-Text Content - Larger Fonts */}
