};

import React, { useState, useEffect } from 'react';

const MOTIVATING_PHRASES = [
  "UPHOLDING THE CONSTITUTION",
  "PURSUING THE TRUTH",
  "BALANCING THE SCALES",
  "EXTRACTING LEGAL WISDOM",
  "NAVIGATING JURISPRUDENCE",
  "PROTECTING RIGHTS",
  "INTERPRETING THE LAW",
  "SEEKING EQUITY"
];

const LEGAL_QUOTES = [
  "Innocent until proven guilty.",
  "Justice delayed is justice denied.",
  "Fiat Justitia Ruat Caelum - Let justice be done though the heavens fall.",
  "Ignorantia juris non excusat - Ignorance of the law excuses no one.",
  "The life of the law has not been logic: it has been experience.",
  "Law is the reason, free from passion.",
  "Stare Decisis - To stand by things decided.",
  "Audi Alteram Partem - Listen to the other side.",
  "Nulla poena sine lege - No penalty without a law.",
  "Actus Reus Non Facit Reum Nisi Mens Sit Rea - The act does not make a person guilty unless the mind is also guilty."
];

export const LoadingGavel = () => {
  const [quoteIndex, setQuoteIndex] = useState(0);
  const [phraseIndex, setPhraseIndex] = useState(0);

  useEffect(() => {
    // Randomize initial quote on mount
    setQuoteIndex(Math.floor(Math.random() * LEGAL_QUOTES.length));

    const quoteInterval = setInterval(() => {
      setQuoteIndex((prev) => (prev + 1) % LEGAL_QUOTES.length);
    }, 4000); 

    const phraseInterval = setInterval(() => {
        setPhraseIndex((prev) => (prev + 1) % MOTIVATING_PHRASES.length);
    }, 2000);

    return () => {
        clearInterval(quoteInterval);
        clearInterval(phraseInterval);
    };
  }, []);

  return (
    <div className="flex flex-col items-center justify-center py-20 overflow-hidden relative min-h-[600px]">

      {/* 3D Gavel Container - Vertical Strike Animation */}
      <div className="relative w-72 h-[450px] mb-16 flex items-end justify-center perspective-[1000px]">

        {/* Sound Block (Base) */}
        <div className="absolute bottom-10 w-64 h-16 bg-[#2a1d15] rounded-lg shadow-[0_20px_50px_rgba(0,0,0,0.8)] border-b-8 border-black flex items-center justify-center z-10">
            <div className="w-[95%] h-[85%] bg-[#3d2b1f] rounded border border-[#5d4037] relative overflow-hidden">
                <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent"></div>
            </div>
        </div>

        {/* The Vertical Gavel */}
        <div className="absolute bottom-[6rem] left-1/2 -translate-x-1/2 z-20 animate-[gavelVerticalStrike_1.5s_cubic-bezier(0.25,1,0.5,1)_infinite]">

          {/* Entire Gavel Assembly - Rigid Construction */}
          <div className="relative flex flex-col items-center">

             {/* Handle - Strictly Vertical */}
             <div className="w-8 h-64 bg-gradient-to-r from-[#2a1d15] via-[#5d4037] to-[#2a1d15] rounded-full shadow-2xl relative z-20 border-x border-white/5">
                 <div className="w-full h-24 bg-black/20 absolute top-0 rounded-t-full backdrop-blur-sm"></div>
                 {/* Grip Texture */}
                 <div className="absolute top-16 w-full flex flex-col gap-2 opacity-40">
                    {[...Array(10)].map((_, i) => <div key={i} className="h-[1px] bg-black w-full"></div>)}
                 </div>
             </div>

             {/* Head - Horizontal at bottom of handle */}
             <div className="w-72 h-28 bg-gradient-to-b from-[#4e342e] to-[#2a1d15] rounded-lg shadow-2xl relative -mt-4 z-30 border-2 border-[#3e2723] flex items-center justify-between px-3">

                {/* Brass End Caps */}
                <div className="h-[90%] w-8 bg-gradient-to-r from-yellow-700 via-yellow-300 to-yellow-700 rounded-sm shadow-inner border border-yellow-900"></div>

