import React, { useState, useEffect, useRef } from 'react';
import { SearchMode, Jurisdiction, HistoryItem } from '../types';

interface HeroSectionProps {
  query: string;
  setQuery: (q: string) => void;
  mode: SearchMode;
  setMode: (m: SearchMode) => void;
  jurisdiction: Jurisdiction;
  setJurisdiction: (j: Jurisdiction) => void;
  onSearch: () => void;
  isLoading: boolean;
  history: HistoryItem[];
  onHistorySelect: (item: HistoryItem) => void;
}

// Mock database for autocomplete demo
const MOCK_CASE_DB = [
  "Kesavananda Bharati v. State of Kerala",
  "Maneka Gandhi v. Union of India",
  "Minerva Mills Ltd. v. Union of India",
  "Golaknath v. State of Punjab",
  "Shah Bano Begum Case",
  "Vishaka v. State of Rajasthan",
  "Puttaswamy v. Union of India (Privacy Case)",
  "Indra Sawhney v. Union of India",
  "ADM Jabalpur v. Shivkant Shukla",
  "S.R. Bommai v. Union of India",
  "Naz Foundation v. Govt. of NCT of Delhi",
  "Navtej Singh Johar v. Union of India",
  "Shayara Bano v. Union of India (Triple Talaq)",
  "M.C. Mehta v. Union of India",
  "Common Cause v. Union of India",
  "D.K. Basu v. State of West Bengal",
  "Mohd. Ahmed Khan v. Shah Bano Begum",
  "Bachchan Singh v. State of Punjab",
  "Olga Tellis v. Bombay Municipal Corporation"
];

export const HeroSection: React.FC<HeroSectionProps> = ({
  query,
  setQuery,
  mode,
  setMode,
  jurisdiction,
  setJurisdiction,
  onSearch,
  isLoading,
  history,
  onHistorySelect
}) => {
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const wrapperRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Autocomplete logic
    if (mode === SearchMode.CASE_NAME && query.length > 2) {
      const filtered = MOCK_CASE_DB.filter(c => 
        c.toLowerCase().includes(query.toLowerCase())
      ).slice(0, 5);
      setSuggestions(filtered);
      setShowSuggestions(filtered.length > 0);
    } else {
      setShowSuggestions(false);
    }
  }, [query, mode]);

  // Click outside to close
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setShowSuggestions(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [wrapperRef]);

  const handleSuggestionClick = (suggestion: string) => {
    setQuery(suggestion);
    setShowSuggestions(false);
  };

  return (
    <div className="relative pt-40 pb-24 px-4 overflow-hidden min-h-[75vh] flex flex-col justify-center bg-[#0f172a]">

      {/* Removed background blur blobs for visual clarity */}

      <div className="max-w-[95rem] mx-auto text-center relative z-10 w-full">

        {/* Logo Section */}
        <div className="mb-20 flex flex-col items-center">

          <div className="relative w-40 h-40 mb-10">
             <svg viewBox="0 0 100 100" className="w-full h-full overflow-visible">
               <path d="M50 10 L85 25 V 55 Q 85 85 50 95 Q 15 85 15 55 V 25 Z" fill="none" stroke="#fbbf24" strokeWidth="4" />
               <path d="M40 25 V 65 Q 40 80 25 80" fill="none" stroke="#fbbf24" strokeWidth="8" strokeLinecap="square" />
               <path d="M60 25 V 80 H 80" fill="none" stroke="#fbbf24" strokeWidth="8" strokeLinecap="square" />
               <line x1="50" y1="20" x2="50" y2="85" stroke="#fbbf24" strokeWidth="4" />
             </svg>
          </div>

          <div className="inline-flex items-center justify-center px-12 py-6 mb-12 border-4 border-gold-500 bg-black">
            <span className="text-gold-400 text-xl font-cinzel tracking-[0.3em] font-black uppercase">
              AI Legal Research
            </span>
          </div>

          <h1 className="font-display text-8xl md:text-[10rem] font-bold mb-10 tracking-tighter text-white drop-shadow-none">
            Juris<span className="italic font-serif text-yellow-500">Lens</span>
          </h1>

          <p className="text-white text-5xl font-serif italic tracking-wide font-medium mt-8">
            "Fiat Justitia Ruat Caelum"
          </p>
        </div>

        {/* Search Interface - MAXIMUM CONTRAST & SIZE */}
        {!isLoading && (
          <div ref={wrapperRef} className="bg-black rounded-none border-4 border-white p-12 max-w-[95rem] mx-auto relative z-50">
            <div className="flex flex-col lg:flex-row gap-8">

              <div className="relative min-w-[320px] bg-black border-4 border-white">
                <select
                  value={mode}
                  onChange={(e) => setMode(e.target.value as SearchMode)}
                  className="w-full h-full p-8 bg-black text-white font-cinzel text-2xl font-black tracking-wider outline-none appearance-none cursor-pointer focus:bg-white focus:text-black transition-colors"
                >
                  <option value={SearchMode.CASE_NAME}>CASE NAME</option>
                  <option value={SearchMode.CITATION}>CITATION</option>
                  <option value={SearchMode.TEXT_ANALYSIS}>RAW TEXT</option>
                </select>
                <div className="absolute right-8 top-1/2 -translate-y-1/2 pointer-events-none text-white">
                  <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M19 9l-7 7-7-7"></path></svg>
                </div>
              </div>

              <div className="flex-grow relative bg-black border-4 border-white">
                {mode === SearchMode.TEXT_ANALYSIS ? (
                  <textarea 
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    placeholder="PASTE JUDGMENT TEXT HERE..."
                    className="w-full p-8 bg-black text-white placeholder-gray-500 outline-none resize-none h-40 leading-relaxed font-serif text-3xl font-bold"
                  />
                ) : (
                  <input
                    type="text"
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && onSearch()}
                    placeholder="SEARCH CASE NAME OR ISSUE..."
                    className="w-full h-full p-8 bg-black text-white placeholder-gray-500 outline-none font-serif text-4xl font-bold tracking-wide"
                    autoComplete="off"
                  />
                )}

                {/* Autocomplete Dropdown - High Contrast */}
                {showSuggestions && (
                  <div className="absolute left-0 right-0 top-full mt-0 bg-black border-4 border-white border-t-0 z-[100]">
                    {suggestions.map((s, i) => (
                      <button 
                        key={i}
                        onClick={() => handleSuggestionClick(s)}
                        className="w-full text-left px-10 py-8 text-white text-3xl hover:bg-white hover:text-black font-serif border-b-2 border-white last:border-0 transition-colors font-bold"
                      >
                        {s}
                      </button>
                    ))}
                  </div>
                )}
              </div>

              {mode !== SearchMode.TEXT_ANALYSIS && (
                 <div className="relative min-w-[280px] bg-black border-4 border-white">
                 <select
                   value={jurisdiction}
                   onChange={(e) => setJurisdiction(e.target.value as Jurisdiction)}
                   className="w-full h-full p-8 bg-black text-white text-xl font-cinzel font-black tracking-widest outline-none appearance-none cursor-pointer focus:bg-white focus:text-black transition-colors uppercase"
                 >
                   {Object.values(Jurisdiction).map((j) => (
                     <option key={j} value={j}>{j}</option>
                   ))}
                 </select>
                 <div className="absolute right-8 top-1/2 -translate-y-1/2 pointer-events-none text-white">
                    <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M19 9l-7 7-7-7"></path></svg>
                 </div>
               </div>
              )}

              <button
                onClick={onSearch}
                disabled={!query.trim()}
                className="bg-yellow-500 hover:bg-yellow-400 disabled:bg-gray-800 disabled:text-gray-500 text-black font-cinzel font-black text-3xl py-8 px-16 transition-all duration-300 flex items-center justify-center gap-4 min-w-[240px] border-4 border-white"
              >
                 <span className="tracking-widest">SEARCH</span>
              </button>
            </div>

            {/* Search History Integration */}
            {history.length > 0 && (
              <div className="mt-12 flex items-center gap-6 overflow-x-auto pb-6 scrollbar-thin">
                <span className="text-xl text-white font-black uppercase tracking-wider shrink-0 mr-4">RECENT:</span>
                {history.map((item, idx) => (
                   <button 
                     key={idx}
                     onClick={() => onHistorySelect(item)}
                     className="shrink-0 flex items-center gap-4 px-8 py-5 bg-black border-2 border-white hover:bg-white hover:text-black group transition-all"
                   >
                     <span className="text-2xl text-white group-hover:text-black font-mono font-bold">{item.query}</span>
                   </button>
                ))}
              </div>
            )}

          </div>
        )}

      </div>
    </div>
  );
};

